insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('business:1-5-stakeholders-in-business:mcq:3215a48c', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'mcq', 'mcq', 1, '{"question": "Tesco acquires one of its major food and drink suppliers. What is the MOST likely effect on Tesco''s customers?", "options": ["They will face higher prices due to reduced competition", "They may benefit from cheaper products as Tesco can lower its supply costs", "They will receive larger orders from Tesco", "They will pay higher dividends to Tesco shareholders"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: B. By acquiring its supplier, Tesco secures supplies at a lower cost. These savings can be passed on to customers through lower prices. Option A is possible in some scenarios but not the most likely direct effect. Option C describes what happens to suppliers, not customers. Option D is irrelevant to customers."}'::jsonb),
('business:1-5-stakeholders-in-business:tf:bbca2eed', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'tf', 'tf', 1, '{"question": "All stakeholders are owners of a business."}'::jsonb, '{"answer": false, "explain": "FALSE. Stakeholders include any group with an interest in the business — customers, employees, suppliers, government and the local community are all stakeholders but none of them are owners. Only the owners (shareholders in a limited company, or the sole trader/partners) are the owners."}'::jsonb),
('business:1-5-stakeholders-in-business:tf:8ae1b5bd', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'tf', 'tf', 1, '{"question": "All businesses have stakeholders."}'::jsonb, '{"answer": true, "explain": "TRUE. Every business, no matter how small, has stakeholders. Even a one-person sole trader has stakeholders — the owner themselves, their customers, suppliers, the local community and the government all have an interest in that business."}'::jsonb),
('business:1-5-stakeholders-in-business:tf:68a05781', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'tf', 'tf', 1, '{"question": "All stakeholders have the same interests."}'::jsonb, '{"answer": false, "explain": "FALSE. Different stakeholder groups have very different and often conflicting interests. For example, owners want to minimise wages (to increase profit), while employees want higher wages. Customers want low prices, while owners want high prices."}'::jsonb),
('business:1-5-stakeholders-in-business:tf:a390acf7', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'tf', 'tf', 1, '{"question": "Stakeholders can influence the activity of a business."}'::jsonb, '{"answer": true, "explain": "TRUE. Stakeholders actively influence businesses. Employees can go on strike; customers can boycott; the government can change laws and taxes; the local community can protest against developments. All of these actions change how the business must operate."}'::jsonb),
('business:1-5-stakeholders-in-business:tf:21a7bdae', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'tf', 'tf', 1, '{"question": "Stakeholders are only interested in the profits of the business."}'::jsonb, '{"answer": false, "explain": "FALSE. Different stakeholders care about very different things. Employees care about wages and job security. Customers care about product quality and price. The local community cares about noise, pollution and local employment. Only the owners/shareholders are primarily motivated by profit."}'::jsonb),
('business:1-5-stakeholders-in-business:tf:34289b45', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'tf', 'tf', 1, '{"question": "Stakeholders generally want a business to succeed."}'::jsonb, '{"answer": true, "explain": "TRUE. Most stakeholders benefit when a business succeeds: employees keep their jobs, suppliers receive orders, the government collects taxes, and the local community benefits from employment and prosperity. However, some specific groups (e.g. competitors, or local residents opposed to a development) may not want a particular business to succeed."}'::jsonb),
('business:1-5-stakeholders-in-business:tf:d31b52b8', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'tf', 'tf', 1, '{"question": "All of the employees of a business are stakeholders."}'::jsonb, '{"answer": true, "explain": "TRUE. Every employee has an interest in the business they work for — they depend on it for their income and job security. Therefore, all employees are stakeholders (specifically, internal stakeholders)."}'::jsonb),
('business:1-5-stakeholders-in-business:tf:b708c953', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'tf', 'tf', 1, '{"question": "A supplier losing a major customer business would not affect them significantly."}'::jsonb, '{"answer": false, "explain": "FALSE. Suppliers are heavily affected when a business they supply to fails or reduces orders. They may lose significant revenue and in extreme cases be put out of business themselves. This is why suppliers want the businesses they supply to continue and grow."}'::jsonb),
('business:1-5-stakeholders-in-business:tf:f78f0a09', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'tf', 'tf', 1, '{"question": "The government benefits when more people are employed by businesses."}'::jsonb, '{"answer": true, "explain": "TRUE. Higher employment means more people paying income tax (more revenue for the government) and fewer people needing unemployment benefits (lower government spending). This is why the government has a strong interest in businesses succeeding and growing."}'::jsonb),
('business:1-5-stakeholders-in-business:tf:0bc1bbcc', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'tf', 'tf', 1, '{"question": "Shareholders and stakeholders are the same thing."}'::jsonb, '{"answer": false, "explain": "FALSE. This is the most common misconception in this topic. Shareholders are one specific type of stakeholder — they are the owners of shares in a limited company. However, stakeholders is a much broader term that includes customers, employees, suppliers, government and the local community. Sole traders and partnerships have no shareholders at all, but they still have many stakeholders."}'::jsonb),
('business:1-5-stakeholders-in-business:tf:30e5812e', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'tf', 'tf', 1, '{"question": "If the government increases income tax, businesses are likely to see higher sales."}'::jsonb, '{"answer": false, "explain": "FALSE. If income tax increases, consumers have less disposable income — meaning they have less money to spend on goods and services. This typically leads to lower sales for businesses, not higher sales. Lower income tax has the opposite effect, boosting consumer spending."}'::jsonb),
('business:1-5-stakeholders-in-business:tf:712bce26', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'tf', 'tf', 1, '{"question": "The local community can force a business to change its plans if there is enough opposition."}'::jsonb, '{"answer": true, "explain": "TRUE. If a local community is sufficiently united in opposing a business development, they can campaign, protest or lobby local authorities, which may result in planning permission being refused or the business changing its proposals. The Heathrow third runway debate is a real-world example of community opposition potentially affecting major business plans."}'::jsonb),
('business:1-5-stakeholders-in-business:learn:b2ea61df', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'learn', 'mcq', 1, '{"readingTitle": "Key Terms & Official Definitions", "reading": "<p>This unit is about understanding who has an interest in a business and how they interact with it. Before studying how stakeholders affect businesses (and vice versa), you must be confident with the following key terms.</p>\n<ul>\n  <li><strong>Stakeholder:</strong> An individual or group of people who have an interest in a business and are affected by, or can affect, its activities.</li>\n  <li><strong>Internal stakeholder:</strong> A stakeholder who is part of the business itself — specifically the owners and employees.</li>\n  <li><strong>External stakeholder:</strong> A stakeholder who exists outside the business — including customers, suppliers, the government and the local community.</li>\n  <li><strong>Shareholder:</strong> An owner of shares in a limited company. All shareholders are stakeholders, but not all stakeholders are shareholders.</li>\n  <li><strong>Dividend:</strong> A share of the profits paid out to shareholders as a reward for their investment.</li>\n  <li><strong>Objective:</strong> A specific goal or target that a stakeholder or business is trying to achieve.</li>\n  <li><strong>Conflicting objectives:</strong> When two or more stakeholder groups want different things from the same business, creating tension or disagreement.</li>\n  <li><strong>Stakeholder influence:</strong> The power a stakeholder group has to change or shape how a business operates.</li>\n</ul>\n<p><strong>⚠️ Common Misconception:</strong> Do NOT confuse <strong>stakeholders</strong> and <strong>shareholders</strong>. A shareholder is one type of stakeholder (an owner of shares). A sole trader has no shareholders — but they are still a stakeholder (as the owner). Getting this wrong in an exam can cost you several marks.</p>", "question": "A sole trader has no shareholders. According to the key terms studied in this topic, does the sole trader still count as having stakeholders?", "options": ["No, because only limited companies can have stakeholders", "Yes, but only if the sole trader also owns shares in their own business", "Yes, stakeholders include anyone with an interest, not just shareholders", "No, because a sole trader has no shareholders and therefore no stakeholders"]}'::jsonb, '{"answer": 2, "explain": "The card states a sole trader has no shareholders but is still a stakeholder as the owner — all shareholders are stakeholders, but not all stakeholders are shareholders."}'::jsonb),
('business:1-5-stakeholders-in-business:learn:1bab842d', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'learn', 'mcq', 1, '{"readingTitle": "Internal vs External Stakeholders", "reading": "<p>Stakeholders are divided into two main categories depending on whether they are inside or outside the business.</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">🏢 Internal Stakeholders</div>\n<div class=\"pro-item\"><strong>Owners:</strong> For a sole trader or partnership, the owner(s) also work in the business. For a limited company, shareholders are the owners. They want profit, growth and a return on their investment.</div>\n<div class=\"pro-item\"><strong>Employees:</strong> Anyone who works for the business — from managers to shop floor workers. They rely on the business for pay, job security, and working conditions.</div>\n</div>\n<div>\n<div class=\"col-head\">🌍 External Stakeholders</div>\n<div class=\"con-item\"><strong>Customers:</strong> People who buy goods/services from the business. They want quality, fair prices and good customer service.</div>\n<div class=\"con-item\"><strong>Suppliers:</strong> Businesses that provide raw materials or goods. They want regular, large, well-paid orders.</div>\n<div class=\"con-item\"><strong>Government:</strong> Wants businesses to pay taxes, create jobs and follow the law.</div>\n<div class=\"con-item\"><strong>Local Community:</strong> Wants businesses to provide jobs, avoid pollution/noise, and contribute to local prosperity.</div>\n</div>\n</div>\n<p>There may be other stakeholders depending on the business — for example, a bank (lender) or a charity partner. The key is always to think about <strong>who has an interest in that specific business</strong>.</p>", "question": "Which of the following is classified as an EXTERNAL stakeholder?", "options": ["An employee working on the shop floor", "A supplier providing raw materials", "A shareholder who works as a company director", "A partner who co-owns the business"]}'::jsonb, '{"answer": 1, "explain": "Suppliers exist outside the business, making them external stakeholders, whereas employees, director-shareholders and owning partners are all internal stakeholders because they are part of the business itself."}'::jsonb),
('business:1-5-stakeholders-in-business:learn:ba2967c2', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'learn', 'mcq', 1, '{"readingTitle": "Objectives of Each Stakeholder Group", "reading": "<p>Each stakeholder group has different goals — and understanding <em>why</em> they have those goals is just as important as knowing what they are.</p>\n<ul>\n  <li><strong>Owners/Shareholders:</strong> To make <strong>profit</strong> and receive dividends. They want the business to grow so their investment increases in value. They may also make decisions to <em>cut costs</em> (e.g. make workers redundant) to protect profits.</li>\n  <li><strong>Employees:</strong> To receive fair <strong>wages</strong>, job <strong>security</strong>, good <strong>working conditions</strong>, and enjoyment from social aspects of work. Employees can go on strike if their needs are not met.</li>\n  <li><strong>Customers:</strong> To receive <strong>quality products</strong> at <strong>affordable prices</strong>, with good customer service and a reliable range of goods. If unhappy, customers simply stop buying.</li>\n  <li><strong>Suppliers:</strong> To receive <strong>large, frequent orders</strong> and be <strong>paid on time</strong>. If the business fails, the supplier also loses income.</li>\n  <li><strong>Government:</strong> To collect <strong>taxes</strong> (income tax, corporation tax, VAT), encourage <strong>employment</strong>, and ensure businesses follow the law. More business activity = more tax revenue = more money for public services.</li>\n  <li><strong>Local Community:</strong> To see a <strong>prosperous, safe and healthy</strong> local area. They want jobs to be created, noise and pollution to be minimised, and businesses to contribute to community projects.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Barratt Developments plc</h4>\n  <p>Barratt is a leading UK house builder. Its shareholders want higher profits and dividends. Its employees want secure, well-paid jobs. Local communities want — or sometimes oppose — new housing developments. The government wants tax revenue and more homes to tackle the housing crisis. Suppliers of bricks, timber and cement want large, reliable orders. Every decision Barratt makes will affect <em>all</em> of these groups differently.</p>\n</div>", "question": "What is a supplier''s main objective when dealing with a business, according to this topic?", "options": ["To receive large, frequent orders paid on time", "To receive dividends from the company''s profits", "To secure job security and fair wages", "To ensure the business follows environmental law"]}'::jsonb, '{"answer": 0, "explain": "The card states suppliers want large, frequent orders and to be paid on time — dividends relate to owners, job security to employees, and legal compliance to government."}'::jsonb),
('business:1-5-stakeholders-in-business:learn:d2ec63e1', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'learn', 'mcq', 1, '{"readingTitle": "Conflicting Objectives Between Stakeholders", "reading": "<p>One of the most important things you need to understand for the exam is that stakeholders often want <strong>different and opposing things</strong>. This creates conflict which can directly affect business decisions.</p>\n<ul>\n  <li><strong>Owners vs Employees:</strong> Owners want to <em>minimise costs</em> to maximise profit — this means keeping wages low. Employees want <em>higher wages</em> and better conditions. This conflict can lead to strikes, which disrupts the business.</li>\n  <li><strong>Owners vs Customers:</strong> Owners want to charge <em>high prices</em> to increase revenue and profit. Customers want <em>low prices</em> and high quality. If prices are too high, customers go to a competitor.</li>\n  <li><strong>Business Growth vs Local Community:</strong> A business expanding its factory creates jobs (positive), but may also increase noise, traffic and pollution (negative), making local residents unhappy.</li>\n  <li><strong>Employees vs Customers:</strong> Employees want higher wages, which increases business costs. To cover these higher costs, the business may raise its prices, meaning customers pay more — directly harming the customer''s objective of affordable prices.</li>\n</ul>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">✓ When Interests Align</div>\n<div class=\"pro-item\">A growing, profitable business benefits owners (higher profit), employees (more jobs), suppliers (more orders), government (more tax) and the local community (more prosperity).</div>\n</div>\n<div>\n<div class=\"col-head\">✗ When Interests Conflict</div>\n<div class=\"con-item\">Cutting the workforce to save costs helps owners (higher profit margin) but harms employees (job losses), local community (unemployment rises) and potentially customers (reduced service).</div>\n</div>\n</div>", "question": "Why do owners and employees often have conflicting objectives, according to this topic?", "options": ["Owners want more competitors in the market while employees want fewer", "Owners want low wage costs for profit; employees want higher pay", "Owners and employees actually always want exactly the same outcome", "Owners want to raise prices while employees want prices lowered"]}'::jsonb, '{"answer": 1, "explain": "The card explains that owners want to minimise costs (keeping wages low) to maximise profit, while employees want higher wages and better conditions — a conflict that can lead to strikes."}'::jsonb),
('business:1-5-stakeholders-in-business:learn:72664234', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'learn', 'mcq', 1, '{"readingTitle": "The Effect Business Activity Has on Stakeholders", "reading": "<p>Business decisions ripple outward and affect many different stakeholders. The same decision can be <strong>positive for some stakeholders and negative for others</strong>.</p>\n<p><strong>When a business GROWS:</strong></p>\n<ul>\n  <li><strong>Employees</strong> — more jobs are created, improving job security and pay prospects.</li>\n  <li><strong>Suppliers</strong> — receive larger, more frequent orders, increasing their own revenue.</li>\n  <li><strong>Government</strong> — collects more tax from the business and its employees; pays less in unemployment benefits.</li>\n  <li><strong>Customers</strong> — benefit from a wider product range and potentially lower prices due to economies of scale.</li>\n  <li><strong>Owners</strong> — earn higher profits and potentially larger dividends.</li>\n  <li><strong>Local Community</strong> — greater employment in the area raises local spending and reduces poverty.</li>\n</ul>\n<p><strong>When a business SHRINKS or CLOSES:</strong></p>\n<ul>\n  <li><strong>Employees</strong> — face redundancy and loss of income.</li>\n  <li><strong>Suppliers</strong> — lose orders; in extreme cases they may also go out of business.</li>\n  <li><strong>Government</strong> — sees fewer tax receipts and must pay more in unemployment benefits.</li>\n  <li><strong>Local Community</strong> — suffers from increased unemployment, reduced local spending, and potential social problems.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Heathrow Third Runway</h4>\n  <p>The proposed expansion of Heathrow Airport illustrates perfectly how the same business activity can affect stakeholders in opposite ways. A third runway would create thousands of jobs (positive for employees and local community), boost import/export opportunities (positive for businesses and government tax), yet also cause significant noise pollution, increased traffic, and environmental damage to local areas (negative for local residents). This is why stakeholder conflicts arise around major developments.</p>\n</div>", "question": "When a business shrinks or closes, what is the most likely effect on the government as a stakeholder?", "options": ["Higher tax receipts from redundancy payments", "No effect, since government revenue depends only on VAT", "Reduced need to spend money on public services", "Lower tax receipts and higher unemployment benefit payments"]}'::jsonb, '{"answer": 3, "explain": "The card states that when a business shrinks or closes, the government sees fewer tax receipts and must pay more in unemployment benefits."}'::jsonb),
('business:1-5-stakeholders-in-business:learn:0890a0e2', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'learn', 'mcq', 1, '{"readingTitle": "The Effect Stakeholders Have on Business", "reading": "<p>Stakeholders do not just passively experience the effects of business decisions — they actively <strong>influence</strong> how a business operates.</p>\n<ul>\n  <li><strong>Owners:</strong> Can make major decisions such as making workers redundant, changing strategy, or investing in growth. Their primary goal of profit drives most major business choices.</li>\n  <li><strong>Employees:</strong> Can go on <strong>strike</strong> to push for higher wages or better conditions. This disrupts production, damages reputation and can cost the business significant revenue. Highly motivated, reliable employees are also the foundation of business success.</li>\n  <li><strong>Customers:</strong> Can <strong>boycott</strong> a business if unhappy with prices, quality or ethics. A customer boycott leads to lower sales, damaged reputation, and reduced profit. Conversely, loyal customers drive growth.</li>\n  <li><strong>Suppliers:</strong> Poor quality or unreliable suppliers can <strong>damage a business''s reputation</strong>. If a supplier to a car manufacturer provides faulty parts, the car maker''s reputation suffers and sales fall.</li>\n  <li><strong>Government:</strong> Can affect business through:\n    <ul>\n      <li>Changing <strong>tax rates</strong> (higher tax = less spending power / less profit to reinvest)</li>\n      <li>Offering <strong>grants</strong> to help businesses establish themselves</li>\n      <li>Changing <strong>laws</strong> (e.g. National Living Wage means businesses must pay more)</li>\n      <li><strong>Government spending</strong> on roads, railways and defence increases business activity</li>\n    </ul>\n  </li>\n  <li><strong>Local Community:</strong> Can <strong>protest or campaign</strong> against business developments they oppose. Sufficient community opposition can force businesses to alter or abandon their plans entirely.</li>\n</ul>", "question": "How can customers most directly influence a business, according to this topic?", "options": ["By setting the level of corporation tax", "By offering grants to help the business grow", "By boycotting the business over price or quality", "By changing employment law"]}'::jsonb, '{"answer": 2, "explain": "The card explains that customers can boycott a business, leading to lower sales, damaged reputation and reduced profit — tax, grants and law changes are actions taken by government."}'::jsonb),
('business:1-5-stakeholders-in-business:learn:f6e998fd', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'learn', 'mcq', 1, '{"readingTitle": "How Government Affects Business — Four Key Methods", "reading": "<p>The government is a uniquely powerful stakeholder because it has <strong>legal authority</strong> over all businesses. It affects business activity in four main ways:</p>\n<div class=\"two-col\">\n<div>\n<div class=\"col-head\">📋 Method 1: Taxation</div>\n<div class=\"pro-item\"><strong>Income tax cuts</strong> leave consumers with more spending money → businesses benefit from higher sales.</div>\n<div class=\"con-item\"><strong>Higher corporation tax</strong> on business profits → less money for reinvestment or dividends.</div>\n<div class=\"col-head\">📋 Method 2: Grants</div>\n<div class=\"pro-item\">Government <strong>grants to businesses</strong> help new firms establish themselves, boosting jobs and economic activity.</div>\n</div>\n<div>\n<div class=\"col-head\">📋 Method 3: Laws & Regulations</div>\n<div class=\"con-item\">The <strong>National Living Wage</strong> forces businesses to pay a minimum level of pay — this increases costs, especially for labour-intensive businesses like retail and hospitality.</div>\n<div class=\"col-head\">📋 Method 4: Government Spending</div>\n<div class=\"pro-item\">Spending on <strong>defence, roads and railways</strong> directly increases business activity and creates opportunities for suppliers and contractors.</div>\n</div>\n</div>\n<p><strong>Exam tip:</strong> When a question asks how government affects business, use one of these four methods — don''t just say \"the government can tax businesses.\" Say <em>which</em> tax and <em>what effect</em> it has on the specific business in the case study.</p>", "question": "Which of these is one of the four key methods by which government affects business, according to this topic?", "options": ["Deciding a business''s individual product prices", "Choosing which suppliers a business must use", "Setting a business''s marketing strategy", "Changing tax rates, such as corporation tax"]}'::jsonb, '{"answer": 3, "explain": "The four methods listed are taxation, grants, laws & regulations, and government spending — government does not set individual prices, marketing strategy or supplier choices for a business."}'::jsonb),
('business:1-5-stakeholders-in-business:learn:5fd5255a', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'learn', 'mcq', 1, '{"readingTitle": "Real-World Application: Stakeholders at Lineside Repairs", "reading": "<div class=\"case-study-box\">\n  <h4>Case Study: Lineside Repairs (Steve Loy''s Garage)</h4>\n  <p>Steve Loy owns Lineside Repairs, a small garage in Elsecar, South Yorkshire. The business has operated since 1968 and services and repairs cars from the local community. Steve employs staff to help with repairs and must keep up to date with changing government regulations, including buying the correct equipment for MOT tests. He must also ensure noise from the business does not disturb nearby residents.</p>\n</div>\n<p><strong>Local Community as a Stakeholder:</strong></p>\n<ul>\n  <li><strong>Understanding:</strong> The local community is concerned about noise and pollution from the garage.</li>\n  <li><strong>Application:</strong> Noise from servicing and testing cars may disturb people living near the garage in Elsecar.</li>\n  <li><strong>Analysis:</strong> If the community protests, Lineside Repairs may have to change its working practices — for example, restricting testing hours — which could reduce its efficiency and profitability.</li>\n</ul>\n<p><strong>Government as a Stakeholder:</strong></p>\n<ul>\n  <li><strong>Understanding:</strong> The government changes regulations on MOT testing requirements.</li>\n  <li><strong>Application:</strong> Lineside Repairs must keep up to date with government regulations and buy the correct equipment to carry out MOT tests.</li>\n  <li><strong>Analysis:</strong> If new MOT regulations are introduced, Steve may need to invest in expensive new equipment. This increases costs significantly and reduces the profit available for the business.</li>\n</ul>", "question": "In the Lineside Repairs case study, after noting that new MOT regulations require expensive new equipment, what should the ''Analysis'' step conclude?", "options": ["A general definition of what an MOT test involves", "The bottom-line impact — higher costs, less profit", "A restatement of the government''s role in setting regulations", "A description of an unrelated stakeholder''s objective"]}'::jsonb, '{"answer": 1, "explain": "The case study analysis shows new MOT regulations force Steve to invest in expensive equipment, increasing costs and reducing the profit available to the business — the analysis step must land on this concrete business impact."}'::jsonb),
('business:1-5-stakeholders-in-business:misc:d5e92d87', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Stakeholders and shareholders are the same thing.</p><p><strong>✅ The correct idea:</strong> Shareholders are just one type of stakeholder — they are owners of shares in a limited company. Stakeholders is a much broader group that includes customers, employees, suppliers, government and the local community. A sole trader has no shareholders but still has many stakeholders. Confusing these two terms in an exam will cost you marks.</p>", "question": "Which statement correctly distinguishes stakeholders from shareholders?", "options": ["Stakeholders and shareholders are two words for the same group of people", "Only shareholders can be affected by what a business does", "Shareholders are one type of stakeholder; not all own shares", "A sole trader cannot have stakeholders because it has no shareholders"]}'::jsonb, '{"answer": 2, "explain": "The card corrects the misconception: shareholders are one type of stakeholder (owners of shares in a limited company), while stakeholders is a much broader group that also includes customers, employees, suppliers, government and the local community."}'::jsonb),
('business:1-5-stakeholders-in-business:misc:5f330e32', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> The local community only cares about getting jobs from a nearby business.</p><p><strong>✅ The correct idea:</strong> The local community has a range of concerns — both positive (employment, local prosperity, community donations) and negative (noise, pollution, traffic congestion, environmental damage). In the exam, you must consider both sides. Do not write that the local community is only interested in charity work.</p>", "question": "According to this card, what should students remember about the local community as a stakeholder?", "options": ["They are only interested in a business''s charity work", "They have no real influence over business decisions", "They are only concerned with gaining new jobs", "They have both positives (jobs) and negatives (noise)"]}'::jsonb, '{"answer": 3, "explain": "The card corrects the misconception that the community ''only cares about jobs'' — in reality they weigh both positives (employment, prosperity) and negatives (noise, pollution, traffic congestion)."}'::jsonb),
('business:1-5-stakeholders-in-business:misc:441e11d8', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> All stakeholders want the business to make as much profit as possible.</p><p><strong>✅ The correct idea:</strong> Only owners and shareholders have profit as a primary objective. Employees want fair wages and job security; customers want low prices and quality; suppliers want reliable, well-paid orders; the local community wants minimal disruption; the government wants tax revenue and legal compliance. Many of these objectives actually conflict with maximising profit.</p>", "question": "Which stakeholder group has profit as its PRIMARY objective, according to this card?", "options": ["Suppliers", "Owners and shareholders", "Employees", "The local community"]}'::jsonb, '{"answer": 1, "explain": "The card explains that only owners/shareholders have profit as a primary objective; other groups such as employees, suppliers, the community and government have different priorities that can actually conflict with maximising profit."}'::jsonb),
('business:1-5-stakeholders-in-business:misc:14c85ea4', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> If a question asks about the impact on employees, you should discuss the impact on the business.</p><p><strong>✅ The correct idea:</strong> The impact must be stakeholder-facing, not business-facing. If asked about the impact on employees, write about wages, job security, working conditions or redundancy — not about business costs or profit. Examiners specifically note this as a common reason for losing marks on 6-mark questions.</p>", "question": "If an exam question asks for the impact on employees, what must the answer focus on?", "options": ["A general description of what the business does", "Effects on employees, such as wages or job security", "The impact on customers instead of employees", "The impact on the business''s costs and profit only"]}'::jsonb, '{"answer": 1, "explain": "The card warns that the impact must be stakeholder-facing, not business-facing — examiners note this is a common reason students lose marks on 6-mark questions."}'::jsonb),
('business:1-5-stakeholders-in-business:misc:b1ad7cb0', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> When a business makes workers redundant, all stakeholders are negatively affected.</p><p><strong>✅ The correct idea:</strong> This is a classic conflicting objectives scenario. Owners/shareholders actually benefit from redundancies because lower wage costs mean higher profit margins and potentially bigger dividends. The negative effects fall on employees (job losses), the local community (unemployment) and government (less tax, more benefits to pay).</p>", "question": "When a business makes workers redundant, which stakeholder group is most likely to actually BENEFIT?", "options": ["Owners, through lower wage costs and higher profit", "Employees, through reduced workloads", "The local community, through lower unemployment", "The government, through reduced benefit payments"]}'::jsonb, '{"answer": 0, "explain": "The card corrects the misconception that redundancies harm everyone — owners/shareholders can benefit from lower wage costs and higher profit margins, while employees, the community and government are negatively affected."}'::jsonb),
('business:1-5-stakeholders-in-business:misc:35a64b16', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Customers only care about getting the cheapest price.</p><p><strong>✅ The correct idea:</strong> Customers care about the overall value they receive — which includes price, product quality, customer service, availability, product range and convenience. In specific contexts, some customers prioritise quality or ethics over price (e.g. choosing ethically-sourced products). Always link customer objectives to the specific business context in the case study.</p>", "question": "According to this card, what do customers actually care about, beyond just getting the cheapest price?", "options": ["Nothing else — price is genuinely their only concern", "Only the ethics of a business, never its prices", "Overall value — quality, service, availability, range", "Only the geographic location of a business''s shops"]}'::jsonb, '{"answer": 2, "explain": "The card corrects the misconception that customers only want the cheapest price — they care about overall value, and some prioritise quality or ethics depending on the context."}'::jsonb),
('business:1-5-stakeholders-in-business:misc:983e71ea', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> External stakeholders are less important than internal stakeholders.</p><p><strong>✅ The correct idea:</strong> There is no hierarchy of importance — it depends entirely on the business and the situation. In many cases, external stakeholders like customers or the government can have a much greater impact on a business than internal stakeholders. For example, new government regulation on MOT tests fundamentally changes what a garage like Lineside Repairs must do.</p>", "question": "According to this card, are external stakeholders always less important than internal stakeholders?", "options": ["Yes — internal stakeholders always have the most influence", "Yes — external stakeholders have no real power over a business", "No — external stakeholders are always more important than internal ones", "No — there is no fixed hierarchy; it depends on the situation"]}'::jsonb, '{"answer": 3, "explain": "The card states there is no hierarchy of importance; external stakeholders like government regulation can sometimes have a far greater impact than internal stakeholders, as shown by the Lineside Repairs MOT example."}'::jsonb),
('business:1-5-stakeholders-in-business:misc:41950f57', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Suppliers are only affected if the business fails completely.</p><p><strong>✅ The correct idea:</strong> Suppliers are affected by any significant change in a business''s orders or financial health. If a business reduces production, the supplier receives smaller orders. If the business faces cash flow problems, the supplier may not be paid on time. Suppliers may even stop supplying goods to a struggling business to protect themselves from losses.</p>", "question": "According to this card, when are suppliers actually affected by a business''s problems?", "options": ["Suppliers are never affected by a business''s financial problems", "Whenever there is a significant change in orders or finances", "Only if the supplier is also a shareholder in the business", "Only if the business closes down entirely"]}'::jsonb, '{"answer": 1, "explain": "The card explains suppliers are affected by any significant change — smaller orders, late payments — not only if the business fails completely."}'::jsonb),
('business:1-5-stakeholders-in-business:tips:177c9682', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'tips', 'mcq', 1, '{"readingTitle": "Identify / State — 1 mark — One Point. Full Stop. Move On.", "reading": "\n      <p>A 1-mark <strong>''Identify'' or ''State''</strong> question needs exactly one correct point. Nothing more. No definitions. No examples. No paragraphs.</p>\n      <p><strong>The Formula:</strong> One specific, accurate point = 1 mark ✅</p>\n      <ul>\n        <li>For <em>\"Identify one likely objective of an employee\"</em> — write: <em>\"To receive a fair wage / To have job security\"</em>. Done.</li>\n        <li>Do NOT write about the business''s objective (profit, growth) — examiners specifically penalise this.</li>\n      </ul>\n      <p><strong>❌ Bad Answer (0 marks):</strong><br/>\n      <em>\"To make the business more profitable.\"</em><br/>\n      This is a business objective, not a personal employee objective. Zero marks.</p>\n      <p><strong>✅ Good Answer (1 mark):</strong><br/>\n      <em>\"To earn a regular income / To have job security.\"</em><br/>\n      This is specific, personal and directly answers the question.</p>\n      <p><strong>⚠️ Examiner Warning:</strong> The most common mistake on 1-mark employee objective questions is writing about profit, greater output or customer service. These relate to business goals, not personal employee objectives.</p>\n    ", "question": "What is required to get full marks on a 1-mark ''Identify'' or ''State'' question?", "options": ["One specific, accurate point with no explanation needed", "A full sentence including a definition and an example", "Two separate points, in case one is wrong", "A detailed paragraph linking the point to the case study"]}'::jsonb, '{"answer": 0, "explain": "The card''s formula is: one specific, accurate point = 1 mark — no definitions, examples or extra explanation are needed or rewarded."}'::jsonb),
('business:1-5-stakeholders-in-business:tips:87ba0b32', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'tips', 'mcq', 1, '{"readingTitle": "Explain — 2 marks — Make Your Point, Then Say Why It Matters", "reading": "\n      <p>A 2-mark <strong>''Explain''</strong> question follows a simple formula: <strong>Knowledge (what) + Application (how/why in context)</strong>.</p>\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li><strong>Point (K — 1 mark):</strong> State the impact/influence clearly.</li>\n        <li><strong>Application (APP — 1 mark):</strong> Link it directly to the specific business in the case study.</li>\n      </ul>\n      <p><strong>❌ Bad Answer (1/2 marks):</strong><br/>\n      <em>\"Customers influence Greggs'' product range.\"</em><br/>\n      This gets the knowledge mark but lacks any application to Greggs'' specific context.</p>\n      <p><strong>✅ Good Answer (2/2 marks):</strong><br/>\n      <em>\"Customers influence Greggs'' product range (K), which led to Greggs launching vegan sausage rolls in 2019 due to the growing number of vegans in the UK (APP).\"</em></p>\n      <p><strong>⚠️ Key Rule:</strong> The application mark requires you to use a specific detail from the case study — a number, a product, a location, a person''s name. Vague references like \"the business\" will NOT earn the application mark.</p>\n    ", "question": "What does a 2-mark ''Explain'' question require, according to the K+APP formula in this card?", "options": ["Two completely separate points, each unrelated to the case study", "A point (K) plus a specific case study link (APP)", "A judgement plus a justification", "Three stakeholder groups each explained briefly"]}'::jsonb, '{"answer": 1, "explain": "The card''s formula for 2-mark ''Explain'' questions is Knowledge (the point) plus Application (linking it to a specific detail in the case study, e.g. Greggs launching vegan sausage rolls)."}'::jsonb),
('business:1-5-stakeholders-in-business:tips:ef9ae365', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'tips', 'mcq', 1, '{"readingTitle": "Analyse — 3 marks — The Holy Trinity: U → APP → AN", "reading": "\n      <p>A 3-mark analyse question is the most common high-tariff question on this topic. You MUST hit all three steps to get full marks. Miss any one of them and you cap yourself at 2 marks maximum.</p>\n      <p><strong>The 3-Step Formula:</strong></p>\n      <ul>\n        <li><strong>Step 1 — Understanding (U — 1 mark):</strong> Show you understand the stakeholder''s interest or impact. Give a relevant example. <br/><em>\"The local community is concerned about noise and pollution from businesses...\"</em></li>\n        <li><strong>Step 2 — Application (APP — 1 mark):</strong> Link that understanding directly to the named business in the case study using a specific detail. <br/><em>\"...Noise from testing and servicing cars at Lineside Repairs could disturb people living in nearby properties in Elsecar...\"</em></li>\n        <li><strong>Step 3 — Analysis (AN — 1 mark):</strong> State the final bottom-line impact ON THE BUSINESS. What does this mean for costs, revenue, profit, reputation? <br/><em>\"...This could force Steve to restrict his operating hours, reducing efficiency and potentially losing customers to competitors.\"</em></li>\n      </ul>\n      <p><strong>🚫 The #1 Reason Students Score 0 for Analysis:</strong> Writing a brilliant general point about the stakeholder but failing to link it back to the specific business. You CANNOT score the analysis mark without first scoring the application mark. No APP = No AN.</p>\n      <p><strong>The \"So What?\" Test:</strong> After every sentence, ask yourself <em>\"So what does this mean for the business?\"</em> Keep asking until you reach a concrete business impact (profit, costs, sales, reputation, closure).</p>\n    ", "question": "In a 3-mark ''Analyse'' answer, what happens if a student skips the Application (APP) step?", "options": ["They can still be awarded the Analysis (AN) mark separately", "They automatically fail the whole question", "They are capped at 2 marks, since AN cannot come without APP", "They lose only the Understanding (U) mark"]}'::jsonb, '{"answer": 2, "explain": "The card states you cannot score the Analysis mark without first scoring the Application mark — ''No APP = No AN'' — so missing APP caps the answer at 2 marks."}'::jsonb),
('business:1-5-stakeholders-in-business:tips:45c4b03f', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'tips', 'mcq', 1, '{"readingTitle": "Analyse 2 Impacts — 6 marks — Two Complete Chains of Analysis — No Conclusion Needed", "reading": "\n      <p>A 6-mark question is simply a <strong>3-mark question done twice</strong>. Write two completely separate, well-structured paragraphs — each one following the U → APP → AN structure.</p>\n      <p><strong>Structure:</strong></p>\n      <ul>\n        <li><strong>Paragraph 1:</strong> Stakeholder Group 1 → Understanding → Application → Analysis</li>\n        <li><strong>Paragraph 2:</strong> Stakeholder Group 2 → Understanding → Application → Analysis</li>\n      </ul>\n      <p><strong>⚠️ Critical Warning — Stakeholder-Facing vs Business-Facing Analysis:</strong><br/>\n      If a question asks for the impact <em>on</em> a stakeholder group (e.g. \"Analyse the impact on two stakeholder groups of the merger\"), your analysis must describe what happens <em>to them</em>, not just what happens to the business.</p>\n      <p><strong>❌ Wrong (business-facing):</strong> \"The merger will reduce costs for Beautiful Buds plc.\"</p>\n      <p><strong>✅ Correct (stakeholder-facing):</strong> \"Employees at Beautiful Buds may face redundancy as the merger creates overlapping roles, meaning they could lose their income and job security.\"</p>\n      <p><strong>🚫 Do NOT write a conclusion</strong> on a 6-mark question. There are zero marks available for evaluation at this level. Save your time for the analysis marks.</p>\n    ", "question": "What is a key rule for 6-mark ''Analyse 2 Impacts'' questions, according to this card?", "options": ["Write one detailed paragraph, then a short conclusion", "Combine both stakeholder groups into a single paragraph", "End with an overall judgement about which stakeholder matters most", "Write two separate U-APP-AN paragraphs with no conclusion"]}'::jsonb, '{"answer": 3, "explain": "The card states a 6-mark question is a 3-mark question done twice — two separate U → APP → AN paragraphs — and warns that no conclusion should be written since there are no evaluation marks available."}'::jsonb),
('business:1-5-stakeholders-in-business:tips:02309050', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'tips', 'mcq', 1, '{"readingTitle": "Recommend / Evaluate — 3 marks — Make a Clear Judgement — Then Justify It With Context", "reading": "\n      <p>A 3-mark evaluate/recommend question on stakeholders follows a specific structure: <strong>Decision + Justification + Contextual Evidence</strong>.</p>\n      <p><strong>The Formula:</strong></p>\n      <ul>\n        <li><strong>Judgement (1 mark):</strong> Make a clear, direct statement about which stakeholder has more/most influence. No explanation required for this mark alone — just a clear choice.</li>\n        <li><strong>Non-contextual justification (1 mark):</strong> Give a reason that is valid for most businesses (not specifically linked to the case study).</li>\n        <li><strong>Contextual justification (up to 2 marks):</strong> Give a reason that uses precise details from the case study. This is the difference between a 2-mark and a 3-mark answer.</li>\n      </ul>\n      <p><strong>❌ ''Sitting on the fence'' = 0 marks:</strong><br/>\n      <em>\"Both the government and the local community affect the business in different ways.\"</em><br/>\n      This does not make a judgement. It answers zero marks.</p>\n      <p><strong>✅ Full marks answer:</strong><br/>\n      <em>\"I think the government has the greater influence on Lineside Repairs (JUDGEMENT). The government can change MOT regulations which Lineside must legally comply with (JUSTIFICATION). If new equipment is required for updated MOT tests, Steve would face a significant investment cost, potentially wiping out profit and threatening the survival of the business (CONTEXTUAL JUSTIFICATION).\"</em></p>\n      <p><strong>Sentence Starters:</strong></p>\n      <ul>\n        <li>\"I think [Stakeholder X] has the greater influence because...\"</li>\n        <li>\"Although [Stakeholder Y] also affects the business, [X] is more significant because...\"</li>\n        <li>\"This depends on the situation, however overall [X] has more impact because...\"</li>\n      </ul>\n    ", "question": "Why does the answer ''Both the government and the local community affect the business in different ways'' score 0 marks on a 3-mark recommend/evaluate question?", "options": ["It never makes a clear judgement or firm decision", "It uses too much case study detail", "It only discusses one stakeholder instead of two", "It does not mention profit"]}'::jsonb, '{"answer": 0, "explain": "The card explains that ''sitting on the fence'' by not choosing a side means the judgement mark cannot be awarded, resulting in 0 marks even if the content is accurate."}'::jsonb),
('business:1-5-stakeholders-in-business:tips:d8cb8466', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'tips', 'mcq', 1, '{"readingTitle": "Explain Objectives — 6 marks — Match the Objective to the Stakeholder AND the Business", "reading": "\n      <p>Questions asking you to \"explain how the objectives of [external] stakeholder groups can be satisfied\" require you to do two things for each stakeholder: state what they want (Understanding) and explain how <em>this specific business</em> meets that need (Application).</p>\n      <p><strong>Key Examiner Rules for this question type:</strong></p>\n      <ul>\n        <li>You must cover <strong>three different stakeholder groups</strong> for the full 6 marks (2 marks per group: 1 for U + 1 for APP).</li>\n        <li>You will receive <strong>no marks for simply naming</strong> the stakeholder group — only for explaining their objective and applying it.</li>\n        <li>If you only write what the stakeholder wants without linking it to the specific business, you cap at 3 marks (one per group, no APP marks).</li>\n        <li>The question says <strong>external</strong> stakeholders — do not write about employees or owners.</li>\n      </ul>\n      <p><strong>❌ Generic Answer (1 mark only per group):</strong><br/>\n      <em>\"Suppliers want to be paid on time.\"</em> — This is valid knowledge but earns only 1 mark with no application.</p>\n      <p><strong>✅ Applied Answer (2 marks):</strong><br/>\n      <em>\"Suppliers want to receive regular, large orders (U). Since Nina''s Knitting Supplies has 10 shops and a website, her orders for knitting wool are likely to be relatively large, giving suppliers the volume they need (APP).\"</em></p>\n      <p><strong>⚠️ Examiner''s Warning:</strong> Do not confuse local community objectives with charity work. The local community wants employment opportunities, reduced noise/pollution, and local prosperity — not charity donations.</p>\n    ", "question": "According to this card, how many marks can a student earn for simply naming a stakeholder group without explaining or applying its objective?", "options": ["3 marks, one for identifying each group correctly", "1 mark per correctly named group", "0 marks — naming the group alone earns nothing", "2 marks, if three groups are named"]}'::jsonb, '{"answer": 2, "explain": "The card states there are ''no marks for simply naming the stakeholder group'' — marks are only earned for explaining the objective (Understanding) and applying it to the business (Application)."}'::jsonb),
('business:1-5-stakeholders-in-business:fib:be7075bd', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'fib', 'fib', 2, '{"question": "A _____ is an individual or group who has an interest in a business, while a _____ is specifically an owner of shares in a limited company.", "blankOptions": {"B1": ["profit", "growth", "frequent", "stakeholder"], "B2": ["investment", "noise", "external", "shareholder"]}}'::jsonb, '{"blanks": {"B1": "stakeholder", "B2": "shareholder"}}'::jsonb),
