('business:1-5-stakeholders-in-business:match:0174d301', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Stakeholder”?", "options": ["A stakeholder who is part of the business itself — specifically the owners and employees who work within it.", "A stakeholder who exists outside the business, including customers, suppliers, the government and the local community.", "An owner of shares in a limited company who receives dividends as a return on their investment.", "An individual or group of people who have an interest in a business and are affected by, or can affect, its activities."]}'::jsonb, '{"answer": 3, "explain": "“Stakeholder” means: An individual or group of people who have an interest in a business and are affected by, or can affect, its activities."}'::jsonb),
('business:1-5-stakeholders-in-business:match:6c78580d', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Internal stakeholder”?", "options": ["A stakeholder who is part of the business itself — specifically the owners and employees who work within it.", "A stakeholder who exists outside the business, including customers, suppliers, the government and the local community.", "An owner of shares in a limited company who receives dividends as a return on their investment.", "A share of the company''s profits paid out to shareholders as a reward for investing their money in the business."]}'::jsonb, '{"answer": 0, "explain": "“Internal stakeholder” means: A stakeholder who is part of the business itself — specifically the owners and employees who work within it."}'::jsonb),
('business:1-5-stakeholders-in-business:match:41929c46', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “External stakeholder”?", "options": ["An owner of shares in a limited company who receives dividends as a return on their investment.", "A share of the company''s profits paid out to shareholders as a reward for investing their money in the business.", "A stakeholder who exists outside the business, including customers, suppliers, the government and the local community.", "When two or more stakeholder groups want different, opposing things from the same business — for example owners wanting low wages while employees want high wages."]}'::jsonb, '{"answer": 2, "explain": "“External stakeholder” means: A stakeholder who exists outside the business, including customers, suppliers, the government and the local community."}'::jsonb),
('business:1-5-stakeholders-in-business:match:19b54bfd', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Shareholder”?", "options": ["A share of the company''s profits paid out to shareholders as a reward for investing their money in the business.", "When two or more stakeholder groups want different, opposing things from the same business — for example owners wanting low wages while employees want high wages.", "An owner of shares in a limited company who receives dividends as a return on their investment.", "When employees refuse to work as a form of protest, usually to pressure business owners into agreeing to better pay or conditions."]}'::jsonb, '{"answer": 2, "explain": "“Shareholder” means: An owner of shares in a limited company who receives dividends as a return on their investment."}'::jsonb),
('business:1-5-stakeholders-in-business:match:470825ed', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Dividend”?", "options": ["A share of the company''s profits paid out to shareholders as a reward for investing their money in the business.", "When two or more stakeholder groups want different, opposing things from the same business — for example owners wanting low wages while employees want high wages.", "When employees refuse to work as a form of protest, usually to pressure business owners into agreeing to better pay or conditions.", "When customers deliberately stop buying a business''s products or services, usually to protest against the business''s practices or pricing."]}'::jsonb, '{"answer": 0, "explain": "“Dividend” means: A share of the company''s profits paid out to shareholders as a reward for investing their money in the business."}'::jsonb),
('business:1-5-stakeholders-in-business:match:7b5b797e', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Conflicting objectives”?", "options": ["When employees refuse to work as a form of protest, usually to pressure business owners into agreeing to better pay or conditions.", "When customers deliberately stop buying a business''s products or services, usually to protest against the business''s practices or pricing.", "A tax the government charges on a business''s profits; if reduced, businesses have more money to reinvest or distribute to owners.", "When two or more stakeholder groups want different, opposing things from the same business — for example owners wanting low wages while employees want high wages."]}'::jsonb, '{"answer": 3, "explain": "“Conflicting objectives” means: When two or more stakeholder groups want different, opposing things from the same business — for example owners wanting low wages while employees want high wages."}'::jsonb),
('business:1-5-stakeholders-in-business:match:8ae084a8', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Strike”?", "options": ["When customers deliberately stop buying a business''s products or services, usually to protest against the business''s practices or pricing.", "A tax the government charges on a business''s profits; if reduced, businesses have more money to reinvest or distribute to owners.", "A legally required minimum hourly rate that businesses must pay their workers, set by the government, which increases business costs.", "When employees refuse to work as a form of protest, usually to pressure business owners into agreeing to better pay or conditions."]}'::jsonb, '{"answer": 3, "explain": "“Strike” means: When employees refuse to work as a form of protest, usually to pressure business owners into agreeing to better pay or conditions."}'::jsonb),
('business:1-5-stakeholders-in-business:match:7f77af26', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Customer boycott”?", "options": ["A tax the government charges on a business''s profits; if reduced, businesses have more money to reinvest or distribute to owners.", "A legally required minimum hourly rate that businesses must pay their workers, set by the government, which increases business costs.", "Money given to a business by the government that does not need to be repaid, used to help new or small businesses establish themselves.", "When customers deliberately stop buying a business''s products or services, usually to protest against the business''s practices or pricing."]}'::jsonb, '{"answer": 3, "explain": "“Customer boycott” means: When customers deliberately stop buying a business''s products or services, usually to protest against the business''s practices or pricing."}'::jsonb),
('business:1-5-stakeholders-in-business:match:6a216a89', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Corporation tax”?", "options": ["A legally required minimum hourly rate that businesses must pay their workers, set by the government, which increases business costs.", "Money given to a business by the government that does not need to be repaid, used to help new or small businesses establish themselves.", "A tax the government charges on a business''s profits; if reduced, businesses have more money to reinvest or distribute to owners.", "The power a stakeholder group has to change or shape how a business operates through their decisions, actions or reactions."]}'::jsonb, '{"answer": 2, "explain": "“Corporation tax” means: A tax the government charges on a business''s profits; if reduced, businesses have more money to reinvest or distribute to owners."}'::jsonb),
('business:1-5-stakeholders-in-business:match:ebc56eff', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “National Living Wage”?", "options": ["A legally required minimum hourly rate that businesses must pay their workers, set by the government, which increases business costs.", "Money given to a business by the government that does not need to be repaid, used to help new or small businesses establish themselves.", "The power a stakeholder group has to change or shape how a business operates through their decisions, actions or reactions.", "An individual or group of people who have an interest in a business and are affected by, or can affect, its activities."]}'::jsonb, '{"answer": 0, "explain": "“National Living Wage” means: A legally required minimum hourly rate that businesses must pay their workers, set by the government, which increases business costs."}'::jsonb),
('business:1-5-stakeholders-in-business:match:f7b2b18d', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Grant”?", "options": ["The power a stakeholder group has to change or shape how a business operates through their decisions, actions or reactions.", "Money given to a business by the government that does not need to be repaid, used to help new or small businesses establish themselves.", "An individual or group of people who have an interest in a business and are affected by, or can affect, its activities.", "A stakeholder who is part of the business itself — specifically the owners and employees who work within it."]}'::jsonb, '{"answer": 1, "explain": "“Grant” means: Money given to a business by the government that does not need to be repaid, used to help new or small businesses establish themselves."}'::jsonb),
('business:1-5-stakeholders-in-business:match:a31d5321', 'business', 'business:1-5-stakeholders-in-business', '1.5 Stakeholders in Business', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Stakeholder influence”?", "options": ["The power a stakeholder group has to change or shape how a business operates through their decisions, actions or reactions.", "An individual or group of people who have an interest in a business and are affected by, or can affect, its activities.", "A stakeholder who is part of the business itself — specifically the owners and employees who work within it.", "A stakeholder who exists outside the business, including customers, suppliers, the government and the local community."]}'::jsonb, '{"answer": 0, "explain": "“Stakeholder influence” means: The power a stakeholder group has to change or shape how a business operates through their decisions, actions or reactions."}'::jsonb),
('business:1-6-business-growth:exam:135ec4d1', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'exam', 'mcq', 1, '{"num": "Q1", "question": "Two vets agree to combine their practices and operate as one business. This is an example of a:", "options": ["Diversification", "Horizontal takeover", "Merger", "Vertical takeover"], "hint": "Did the two businesses agree, or did one buy the other? Also consider whether they are in the same or different industries.", "starter": "The correct answer is C because..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Merger [1 mark]</h5><p><strong>Why C is correct:</strong> Both practices mutually agreed to combine — this is the definition of a merger. It is not a takeover because neither business bought control of the other.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Diversification:</strong> Both are in the same industry (veterinary), not unrelated industries.</li><li><strong>B — Horizontal takeover:</strong> Although horizontal (same industry), the businesses agreed to combine — making it a merger, not a takeover. A takeover requires one buying control of the other.</li><li><strong>D — Vertical takeover:</strong> The businesses are at the same stage of the same industry, not at different stages of a supply chain.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:1-6-business-growth:exam:6335da63', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'exam', 'mcq', 1, '{"num": "Q5", "question": "Eve is a restaurant owner. She has successfully used social media to attract a lot of new customers to eat in her restaurant. This is an example of:", "options": ["Diversification", "Invention", "Organic growth", "Skimming"], "hint": "Has Eve merged with or bought another business? Or has she grown her customer base from within using her own marketing?", "starter": "The correct answer is C because..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\"><h5>Answer: C — Organic growth [1 mark]</h5><p><strong>Why C is correct:</strong> Eve has grown her business internally by improving marketing (social media). Gaining new customers through marketing is organic growth — no external business was involved.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Diversification:</strong> Involves merging with/taking over a business in an unrelated industry. Eve has not joined with any other business.</li><li><strong>B — Invention:</strong> Creating a brand new product or service. Eve has not invented anything — she is just marketing her existing restaurant.</li><li><strong>D — Skimming:</strong> A pricing strategy where a high initial price is charged for a new product. Eve is using a marketing strategy, not a pricing strategy.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:1-6-business-growth:exam:5effbbc0', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'exam', 'mcq', 1, '{"num": "Q6", "question": "A manufacturer of jam buys a fruit farm. This is an example of:", "options": ["A business partnership", "A vertical takeover", "Diversification", "Flexible working"], "hint": "The fruit farm supplies the raw materials (fruit) to the jam maker. Is the jam maker moving backward or forward in the supply chain?", "starter": "The correct answer is B because..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B — A vertical takeover [1 mark]</h5><p><strong>Why B is correct:</strong> The jam manufacturer is buying its supplier (the fruit farm), moving backwards up the supply chain. Since one business is buying the other (not a mutual agreement), it is a takeover. Backward vertical + takeover = vertical takeover.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — A business partnership:</strong> A partnership is a type of business ownership structure, not a form of external growth.</li><li><strong>C — Diversification:</strong> Diversification means buying a business in a completely unrelated industry. A fruit farm directly supplies the jam maker — they are connected, so this is vertical not diversification.</li><li><strong>D — Flexible working:</strong> Flexible working is an HR concept about working patterns. Entirely unrelated to business growth.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:1-6-business-growth:exam:30212ada', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'exam', 'mcq', 1, '{"num": "Q7", "question": "A business has gained more customers by improving the way it markets its products. Which one of the following statements must be true for this business?", "options": ["The business has developed a new product", "The business has grown organically", "The business has increased its market share", "The business has made a profit"], "hint": "Focus on the word ''must''. Only one of these is definitely true in ALL cases when a business gains customers through better marketing.", "starter": "The correct answer is B because..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B — The business has grown organically [1 mark]</h5><p><strong>Why B is correct:</strong> Gaining customers through improved marketing is internal to the business — this is organic growth by definition. This MUST be true because the business has grown from within, without any external acquisition.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Developed a new product:</strong> Not necessarily — better marketing could be for existing products. No new product was needed.</li><li><strong>C — Increased its market share:</strong> Not necessarily. If the total market grew faster than the business, its market share could actually have fallen even though it gained more customers.</li><li><strong>D — Made a profit:</strong> Not necessarily — the business may have high costs elsewhere and still operate at a loss despite gaining more customers.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:1-6-business-growth:exam:c2e1bff3', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'exam', 'mcq', 1, '{"num": "Q9", "question": "A well-known restaurant chain buys another well-known restaurant chain. What is this an example of?", "options": ["A horizontal takeover", "A vertical merger", "Diversification", "Innovation"], "hint": "Both businesses are restaurant chains. One is BUYING the other. Are they at the same or different stages of production?", "starter": "The correct answer is A because..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\"><h5>Answer: A — A horizontal takeover [1 mark]</h5><p><strong>Why A is correct:</strong> Both businesses are restaurant chains — same industry, same stage of production = horizontal. One is buying the other (not mutual agreement) = takeover. Horizontal + takeover = horizontal takeover.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>B — A vertical merger:</strong> Vertical means different stages of the supply chain (e.g., restaurant buying a food supplier). Both are restaurants = same stage = horizontal. Also ''buys'' = takeover, not a mutual merger.</li><li><strong>C — Diversification:</strong> Diversification means entering an unrelated industry. Both are in the restaurant industry.</li><li><strong>D — Innovation:</strong> Innovation = developing new products or processes. Buying another business is not innovation.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:1-6-business-growth:exam:9ef077fc', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'exam', 'mcq', 1, '{"num": "Apple MCQ", "question": "Which of the following statements describes a takeover?", "options": ["Orange and T-Mobile joined together to become EE", "Disney the film-maker bought the cartoon animation company Pixar", "Honda Motor Company builds a factory to manufacture gear boxes for its cars", "Netflix increases its share of the market"], "caseStudy": "Apple was started in 1976 and is now the largest company in the world. It began by making and selling desktop computers and its first order was for 50 computers sold at $666 each, bringing in revenue of $33,300. In 2016, its revenue had grown to $49.6bn — a huge increase, even allowing for price rises since 1976. During its history, Apple has taken over only a very small number of other businesses. Apple has researched and developed a range of successful products, including laptop computers such as the MacBook Pro, mobile phones (iPhone), tablet computers (iPad) and services such as Apple Pay. Apple has run some very effective marketing campaigns. It often introduces new products around September and advertises them heavily in the lead-up to Christmas. Its advertising is very innovative, using catchy music, a confident narrator and minimalistic backgrounds in order to focus attention on its products.", "hint": "A takeover is when one business PURCHASES control of another. Look for a scenario where money was paid to acquire another company.", "starter": "The correct answer is B because..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\"><h5>Answer: B — Disney bought Pixar [1 mark]</h5><p><strong>Why B is correct:</strong> Disney acquired (purchased) Pixar — one business buying a controlling interest in another is a takeover.</p><p><strong>Why the other options are wrong:</strong></p><ul><li><strong>A — Orange and T-Mobile:</strong> They joined together by mutual agreement — this is a merger, not a takeover.</li><li><strong>C — Honda builds a factory:</strong> Building new production capacity is internal/organic growth — Honda is not buying another business.</li><li><strong>D — Netflix increases market share:</strong> Growing market share through better products or marketing is organic growth, not a takeover of another business.</li></ul></div>", "modelAnswer": ""}'::jsonb),
('business:1-6-business-growth:mcq:135ec4d1', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'mcq', 'mcq', 1, '{"question": "Two vets agree to combine their practices and operate as one business. This is an example of a:", "options": ["Horizontal takeover", "Vertical takeover", "Merger", "Diversification"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: C — Merger. Both vet practices mutually agreed to combine — this is the definition of a merger. It is not a takeover because neither bought the other. It is horizontal (same industry) but since they agreed to join, it is a merger not a takeover."}'::jsonb),
('business:1-6-business-growth:mcq:3a9be807', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'mcq', 'mcq', 1, '{"question": "Eve is a restaurant owner. She has successfully used social media to attract a lot of new customers. This is an example of:", "options": ["Invention", "Organic growth", "Diversification", "Skimming"]}'::jsonb, '{"answer": 1, "explain": "Correct answer: C — Organic growth. Eve has grown her business internally by using better marketing (social media) to gain new customers. Gaining customers through marketing is a classic organic growth method. A: Diversification = merging with an unrelated business. B: Invention = creating a new product. D: Skimming = a pricing strategy."}'::jsonb),
('business:1-6-business-growth:mcq:5effbbc0', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'mcq', 'mcq', 1, '{"question": "A manufacturer of jam buys a fruit farm. This is an example of:", "options": ["A vertical takeover", "Flexible working", "Diversification", "A business partnership"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: B — A vertical takeover. The jam manufacturer is buying its supplier (the fruit farm), moving backwards up the supply chain — backward vertical external growth. A: A partnership is a type of business ownership, not a growth strategy. C: Diversification would mean entering an unrelated industry — fruit and jam are directly connected. D: Flexible working is an HR concept."}'::jsonb),
('business:1-6-business-growth:mcq:43c0f9f3', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'mcq', 'mcq', 1, '{"question": "A business has gained more customers by improving the way it markets its products. Which statement must be true?", "options": ["The business has grown organically", "The business has made a profit", "The business has developed a new product", "The business has increased its market share"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: B — The business has grown organically. Improving marketing to gain customers is an internal method of growth — this is always organic growth. A: Not necessarily — marketing may be for existing products. C: Not necessarily — the total market may have grown faster, so market share could have fallen. D: Not necessarily — the business may still have higher costs."}'::jsonb),
('business:1-6-business-growth:mcq:c2e1bff3', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'mcq', 'mcq', 1, '{"question": "A well-known restaurant chain buys another well-known restaurant chain. What is this an example of?", "options": ["A horizontal takeover", "Diversification", "Innovation", "A vertical merger"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: A — A horizontal takeover. Both businesses are restaurant chains — same stage, same industry = horizontal. One is buying the other (not mutual agreement) = takeover. B: Vertical = different stages of supply chain. C: Diversification = unrelated industry. D: Innovation = new products or processes."}'::jsonb),
('business:1-6-business-growth:mcq:f065dd19', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'mcq', 'mcq', 1, '{"question": "Which of the following is NOT an example of organic growth?", "options": ["Merging with a supplier", "Gaining new customers", "Increasing output", "Developing new products"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: B — Merging with a supplier. Merging with any other business is always external (inorganic) growth, regardless of whether it is a supplier, customer or rival. Options A, C, and D are all internal methods of growing the business from within."}'::jsonb),
('business:1-6-business-growth:mcq:868e7732', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'mcq', 'mcq', 1, '{"question": "A business increasing its market share would normally lead to the business having:", "options": ["A better reputation", "A better workforce", "A guarantee of supplies", "More customers"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: A — More customers. Market share measures the proportion of total market sales held by the business. If market share increases, the business holds a larger slice of the market, which means more customers relative to rivals. The other options are not direct consequences of increased market share."}'::jsonb),
('business:1-6-business-growth:mcq:4fbd43d2', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'mcq', 'mcq', 1, '{"question": "A forwards vertical merger is when:", "options": ["A business merges with a supplier", "A business merges with another similar business", "A business merges with a totally different business", "A business merges with a business it supplies goods to"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: C — A business merges with a business it supplies goods to. Forward vertical = moving forward down the supply chain towards the customer. A: Merging with a similar business is horizontal. B: Merging with a supplier is backward vertical. D: Merging with a totally different business is diversification."}'::jsonb),
('business:1-6-business-growth:mcq:6ac4ba0f', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'mcq', 'mcq', 1, '{"question": "A takeover is when:", "options": ["A business buys more than 50% of another business", "A business agrees to join with another business", "A business buys any share of another business", "A business takes over paying the workers at another business"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: B — A business buys more than 50% of another business. Owning more than 50% gives a controlling interest — the buyer can outvote all other shareholders on key decisions. A: Agreeing to join is a merger. C: Buying any share does not give control. D: This is not a business growth concept."}'::jsonb),
('business:1-6-business-growth:mcq:3b322834', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'mcq', 'mcq', 1, '{"question": "Which of the following describes a takeover?", "options": ["Netflix increases its share of the market", "Honda Motor Company builds a factory to manufacture gear boxes for its cars", "Disney the film-maker bought the animation company Pixar", "Orange and T-Mobile joined together to become EE"]}'::jsonb, '{"answer": 2, "explain": "Correct answer: B — Disney buying Pixar. A takeover is when one business purchases a controlling interest in another. Disney acquired (bought) Pixar. A: Orange and T-Mobile agreed to join — that is a merger. C: Building a new factory is organic growth (increasing capacity internally). D: Netflix growing market share organically is organic growth."}'::jsonb),
('business:1-6-business-growth:mcq:ac9fe9a0', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'mcq', 'mcq', 1, '{"question": "Which of the following is NOT a method of external growth?", "options": ["Developing a new product range", "Horizontal merger", "Backward vertical takeover", "Diversification"]}'::jsonb, '{"answer": 0, "explain": "Correct answer: C — Developing a new product range. Developing new products internally is a method of organic (internal) growth. Options A, B, and D all involve joining with or buying another business, making them forms of external growth."}'::jsonb),
('business:1-6-business-growth:mcq:a975aa77', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'mcq', 'mcq', 1, '{"question": "A business assembling computers merges with a microchip supplier. This is an example of:", "options": ["Horizontal growth", "Forward vertical growth", "Diversification", "Backward vertical growth"]}'::jsonb, '{"answer": 3, "explain": "Correct answer: B — Backward vertical growth. The computer assembler is buying its supplier (the microchip company), moving backwards up the supply chain. A: Horizontal would mean both do the same thing. C: Forward vertical would be buying a retailer that sells the computers. D: Diversification would mean an entirely unrelated industry."}'::jsonb),
('business:1-6-business-growth:tf:4a2ae400', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'tf', 'tf', 1, '{"question": "Organic growth in a business is about growing vegetables organically."}'::jsonb, '{"answer": false, "explain": "FALSE. Organic growth means the internal growth of a business — growing from within by increasing sales, developing products, or gaining customers. The word ''organic'' here means ''natural/internal'', not agricultural."}'::jsonb),
('business:1-6-business-growth:tf:4f6d85a6', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'tf', 'tf', 1, '{"question": "More effective marketing will help a business grow."}'::jsonb, '{"answer": true, "explain": "TRUE. Better marketing attracts new customers and increases sales — a classic method of organic growth. It helps the business grow revenue and potentially its market share."}'::jsonb),
('business:1-6-business-growth:tf:864ce7b5', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'tf', 'tf', 1, '{"question": "Market share is the share a worker has in the business."}'::jsonb, '{"answer": false, "explain": "FALSE. Market share is the proportion of total market sales held by one business, expressed as a percentage. It has nothing to do with employees. A ''share'' in a company is a unit of ownership — a completely different concept."}'::jsonb),
('business:1-6-business-growth:tf:871a1803', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'tf', 'tf', 1, '{"question": "A merger is when one business buys a controlling interest in another business."}'::jsonb, '{"answer": false, "explain": "FALSE. A merger is when two businesses mutually agree to join together. When one business purchases a controlling interest (over 50% of shares), that is a takeover. The key difference is mutual agreement vs one business buying control."}'::jsonb),
('business:1-6-business-growth:tf:4bfca884', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'tf', 'tf', 1, '{"question": "With a 30% increase in the total market, a business that increases its sales by 20% will have increased its market share."}'::jsonb, '{"answer": false, "explain": "FALSE. Market share is relative to the total market. If the total market grew by 30% but the business only grew by 20%, the business''s market share has actually decreased — it is growing more slowly than the market overall."}'::jsonb),
('business:1-6-business-growth:tf:cc16e37f', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'tf', 'tf', 1, '{"question": "External growth is always a better method of growth than organic growth."}'::jsonb, '{"answer": false, "explain": "FALSE. Whether external or organic growth is better depends entirely on the context. External growth is faster but more expensive and risky. Organic growth is slower but cheaper and retains owner control. The best method depends on the business''s objectives, finances, and the competitiveness of its market."}'::jsonb),
('business:1-6-business-growth:tf:e4290dde', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'tf', 'tf', 1, '{"question": "A backward vertical takeover involves a business buying a company it sells its products to."}'::jsonb, '{"answer": false, "explain": "FALSE. Backward vertical means buying a supplier — a business that provides goods or services to you. Buying a business you sell to is forward vertical growth. Remember: backward = moving back up the supply chain towards suppliers."}'::jsonb),
('business:1-6-business-growth:tf:1c912ce0', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'tf', 'tf', 1, '{"question": "Horizontal growth occurs when two businesses at the same stage of production in the same industry combine."}'::jsonb, '{"answer": true, "explain": "TRUE. Horizontal growth is exactly this — two businesses doing the same thing joining together, whether as a merger or takeover. Examples: two competing supermarkets merging, or two rival car wash businesses."}'::jsonb),
('business:1-6-business-growth:tf:b4c2329f', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'tf', 'tf', 1, '{"question": "Organic growth is less risky than external growth."}'::jsonb, '{"answer": true, "explain": "TRUE. Organic growth uses internal resources and grows at a manageable pace, reducing financial risk. External growth involves large upfront costs, potential management difficulties, and culture clashes — making it inherently riskier."}'::jsonb),
('business:1-6-business-growth:tf:230fb5d9', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'tf', 'tf', 1, '{"question": "A takeover requires a business to buy more than 50% of the shares in another business to gain a controlling interest."}'::jsonb, '{"answer": true, "explain": "TRUE. Owning more than 50% means the buyer can outvote all other shareholders on any decision, giving it full control over the business''s direction and strategy."}'::jsonb),
('business:1-6-business-growth:tf:2d762a20', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'tf', 'tf', 1, '{"question": "Diversification involves a business merging with a direct competitor in the same industry."}'::jsonb, '{"answer": false, "explain": "FALSE. Diversification is when a business joins with a company in a completely different, unrelated industry. Joining with a direct competitor would be horizontal growth — they are in the same market."}'::jsonb),
('business:1-6-business-growth:tf:5d6b3d1a', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'tf', 'tf', 1, '{"question": "It is important for technology-based businesses to constantly bring out new products if they are to grow."}'::jsonb, '{"answer": true, "explain": "TRUE. In the technology sector, products quickly become outdated. Businesses like Apple rely on constant research and development (e.g. new iPhone models each year) to stay competitive and continue growing organically through product development."}'::jsonb),
('business:1-6-business-growth:learn:fd192647', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'learn', 'mcq', 1, '{"readingTitle": "Key Terms & Official Definitions", "reading": "<p>This sub-topic covers the ways in which a business can increase in size — either by growing from within (<strong>organic/internal growth</strong>) or by joining with or buying other businesses (<strong>external growth</strong>).</p>\n<ul>\n  <li><strong>Organic Growth:</strong> Concerned with the <em>internal</em> growth of a business, e.g. by increasing sales, developing new products, or gaining new customers — without joining with another business.</li>\n  <li><strong>External Growth:</strong> The growth of a business by <em>takeover or merger</em> with another business.</li>\n  <li><strong>Merger:</strong> Where two or more businesses <em>mutually agree</em> to join together to become one new business.</li>\n  <li><strong>Takeover:</strong> Where a business takes a <em>controlling interest</em> in another business, for example by buying more than 50% of the shares in it.</li>\n  <li><strong>Horizontal Growth:</strong> A merger or takeover where the two businesses are involved in a <em>similar operation at the same stage of production</em> in the same industry.</li>\n  <li><strong>Backward Vertical Growth:</strong> When a business merges with, or takes over, a business that <em>supplies</em> it with goods or services — moving back up the supply chain.</li>\n  <li><strong>Forward Vertical Growth:</strong> When a business merges with, or takes over, a business that it <em>supplies goods or services to</em> — moving forward down the supply chain.</li>\n  <li><strong>Diversification:</strong> When a business merges with or takes over another business with which it has <em>no connection</em> — entering a completely new market.</li>\n  <li><strong>Market Share:</strong> A business''s sales as a percentage of total market sales. Formula: (Business Sales ÷ Total Market Sales) × 100.</li>\n</ul>", "question": "A business merges with a company in a completely unrelated industry, such as a clothing brand buying a software firm. What type of growth is this?", "options": ["Horizontal growth", "Backward vertical growth", "Forward vertical growth", "Diversification"]}'::jsonb, '{"answer": 3, "explain": "Diversification is defined as merging with or taking over a business with no connection, entering a completely new market."}'::jsonb),
('business:1-6-business-growth:learn:5cbd5ed6', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'learn', 'mcq', 1, '{"readingTitle": "Organic (Internal) Growth — Methods", "reading": "<p><strong>Organic growth</strong> means expanding using the business''s own internal resources and capabilities, without merging with or acquiring another business. It is generally a slower but safer form of growth.</p>\n<ul>\n  <li><strong>Increasing Output:</strong> The business produces more — by using resources more efficiently, using spare capacity, or building new factories and expanding premises.</li>\n  <li><strong>Developing New Products:</strong> The business researches and develops new products, buys ideas/licences from others, or copies successful concepts from competitors. Technology businesses like Apple rely heavily on this.</li>\n  <li><strong>Gaining New Customers:</strong> The business attracts customers it did not previously have by reducing prices, opening new shops, or investing in better marketing and advertising.</li>\n  <li><strong>Increasing Market Share:</strong> The business wins a larger proportion of total market sales from rivals through better pricing, quality, or marketing.</li>\n</ul>\n<div class=\"case-study-box\">\n  <h4>Case Study: Pets at Home</h4>\n  <p>Pets at Home achieved organic growth by <strong>expanding the range of services it offers internally</strong> — including grooming services and veterinary services. Rather than buying other businesses, it grew by developing new revenue streams within its existing brand and customer base, attracting new customer segments who need pet care beyond just products.</p>\n  <p><strong>Takeaway:</strong> Adding new services to an existing customer base is a classic method of organic growth — no mergers required.</p>\n</div>", "question": "Which of the following is an example of organic (internal) growth?", "options": ["A business buys a controlling stake in a rival firm", "A business develops a new product via its own research", "Two businesses agree to merge into one new company", "A business takes over its main supplier"]}'::jsonb, '{"answer": 1, "explain": "Organic growth expands the business using its own internal resources, such as developing new products, without merging with or acquiring another business."}'::jsonb),
('business:1-6-business-growth:learn:c0cbf42b', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'learn', 'mcq', 1, '{"readingTitle": "External (Inorganic) Growth — Mergers & Takeovers", "reading": "<p><strong>External growth</strong> happens when a business joins with or buys another business. It is a faster way to grow but carries higher risk and cost.</p>\n<ul>\n  <li><strong>Merger:</strong> Two businesses <em>mutually agree</em> to combine and form one new business. Neither forces the other. Example: Orange + T-Mobile agreeing to form EE.</li>\n  <li><strong>Takeover (Acquisition):</strong> One business <em>buys a controlling stake</em> (over 50% of shares) in another, often without the target having a choice. Example: Disney buying Pixar.</li>\n</ul>\n<p><strong>Key difference:</strong> A merger is by <strong>mutual agreement</strong>; a takeover is where one business gains <strong>control</strong> over another by purchasing shares.</p>\n<div class=\"formula-box\">\n  <strong>Supply Chain Direction (Memory Aid):</strong><br>\n  Supplier &rarr; Manufacturer &rarr; Retailer &rarr; Customer<br>\n  <strong>Backward vertical</strong> = buying your supplier (moving ← left)<br>\n  <strong>Forward vertical</strong> = buying your retailer/customer (moving → right)<br>\n  <strong>Horizontal</strong> = buying a business at the same level as you<br>\n  <strong>Diversification</strong> = buying a business in a completely unrelated industry\n</div>", "question": "What is the key difference between a merger and a takeover?", "options": ["A merger only happens between competitors, while a takeover only happens between suppliers", "A merger is always cheaper than a takeover", "A takeover always results in a completely new company name being formed", "A merger is mutual agreement; a takeover is buying a controlling stake"]}'::jsonb, '{"answer": 3, "explain": "A merger is by mutual agreement, whereas a takeover is where one business gains control by purchasing over 50% of another''s shares, often without the target having a choice."}'::jsonb),
('business:1-6-business-growth:learn:73da6118', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'learn', 'mcq', 1, '{"readingTitle": "Types of External Growth", "reading": "<p>External growth can take several forms depending on the <strong>relationship between the two businesses</strong> involved:</p>\n<ul>\n  <li><strong>Horizontal Growth:</strong> Two businesses at the <em>same stage of production in the same industry</em> join together. Example: A business making radios merges with a business making televisions. Example: Two rival restaurant chains merging.</li>\n  <li><strong>Backward Vertical Growth:</strong> A business joins with a <em>supplier</em>. Example: A computer assembler merges with a microchip supplier. Example: A jam manufacturer buys a fruit farm.</li>\n  <li><strong>Forward Vertical Growth:</strong> A business joins with a business it <em>sells to</em>. Example: A pottery maker takes over a pottery shop. Example: Greggs merging with a sandwich retailer.</li>\n  <li><strong>Diversification:</strong> A business joins a company in a <em>completely different, unrelated industry</em>. Example: A clothing company buying a software firm.</li>\n</ul>\n<p>The table below shows key examples to help you remember:</p>\n<ul>\n  <li>Jam maker + fruit farm = <strong>Backward vertical</strong> (farm supplies fruit)</li>\n  <li>Potter + pottery shop = <strong>Forward vertical</strong> (shop sells the pottery)</li>\n  <li>Radio maker + TV maker = <strong>Horizontal</strong> (same industry, same stage)</li>\n  <li>Clothing brand + tech firm = <strong>Diversification</strong> (no connection)</li>\n</ul>", "question": "A potter (pottery maker) takes over the shop that sells its pottery to customers. What type of external growth is this?", "options": ["Backward vertical growth", "Diversification", "Forward vertical growth", "Horizontal growth"]}'::jsonb, '{"answer": 2, "explain": "Forward vertical growth occurs when a business joins with a business it sells to — here the potter joins the shop it supplies pottery to, moving forward down the supply chain."}'::jsonb),
('business:1-6-business-growth:learn:b36eb43c', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'learn', 'mcq', 1, '{"readingTitle": "Advantages & Disadvantages: Organic vs External Growth", "reading": "<p>Both forms of growth have clear benefits and drawbacks. In the exam you may be asked to <strong>analyse</strong> or <strong>evaluate</strong> which method is more appropriate for a specific business.</p>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Advantages of Organic Growth</div>\n    <div class=\"pro-item\"><strong>Less risky:</strong> The business grows at a pace it can manage, reducing the chance of financial overextension.</div>\n    <div class=\"pro-item\"><strong>Maintains control:</strong> Owners retain full strategic control and decision-making authority — profits do not need to be shared with new partners.</div>\n    <div class=\"pro-item\"><strong>Builds own expertise:</strong> The business develops its own skills and brand identity, leading to a stronger competitive position over time.</div>\n    <div class=\"pro-item\"><strong>Lower cost:</strong> Funded through internal funds (retained profit), avoiding the large upfront costs of buying another business.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Disadvantages of Organic Growth</div>\n    <div class=\"con-item\"><strong>Slow:</strong> Takes much longer to achieve significant growth — shareholders may prefer faster expansion to boost returns more quickly.</div>\n    <div class=\"con-item\"><strong>Limited growth potential:</strong> In a competitive or saturated market there may be a ceiling to how much the business can grow from within.</div>\n    <div class=\"con-item\"><strong>Competitors may overtake:</strong> Rivals using external growth can gain market share far more rapidly, potentially leaving organic growers behind.</div>\n  </div>\n</div>\n<div class=\"two-col\">\n  <div>\n    <div class=\"col-head\">✓ Advantages of External Growth</div>\n    <div class=\"pro-item\"><strong>Fast:</strong> Market share and revenue can increase almost immediately, satisfying impatient shareholders and investors.</div>\n    <div class=\"pro-item\"><strong>Reduces competition:</strong> Taking over or merging with a rival removes a competitor from the market — potentially allowing higher prices.</div>\n    <div class=\"pro-item\"><strong>Access to expertise:</strong> The business instantly gains the skills, technology, customer base and reputation of the acquired business.</div>\n    <div class=\"pro-item\"><strong>Economies of scale:</strong> A larger combined business can negotiate bulk discounts, spread fixed costs, and lower unit costs.</div>\n  </div>\n  <div>\n    <div class=\"col-head\">✗ Disadvantages of External Growth</div>\n    <div class=\"con-item\"><strong>Very expensive:</strong> Buying another business requires significant investment or borrowing, greatly increasing financial risk.</div>\n    <div class=\"con-item\"><strong>Loss of control:</strong> In a merger, profits and decisions must be shared with other owners — disagreements and conflict can arise.</div>\n    <div class=\"con-item\"><strong>Management challenges:</strong> Managers may lack the experience to run a much larger, more complex organisation, leading to inefficiency and wasted money.</div>\n    <div class=\"con-item\"><strong>Culture clashes:</strong> Employees from different businesses may have conflicting values or working practices, reducing productivity.</div>\n  </div>\n</div>", "question": "Which of these is listed as a key advantage of organic growth over external growth?", "options": ["Competition in the market is reduced", "Owners maintain full strategic control without having to share profits", "Market share increases almost immediately", "The business gains instant access to a rival''s expertise and customer base"]}'::jsonb, '{"answer": 1, "explain": "The card lists ''maintains control'' as an advantage of organic growth, since owners retain full decision-making authority; the other options are listed as advantages of external growth instead."}'::jsonb),
('business:1-6-business-growth:learn:ad820f53', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'learn', 'mcq', 1, '{"readingTitle": "Market Share — Formula & Calculations", "reading": "<p>Market share measures a business''s dominance within its market. Increasing market share means the business is winning customers from rivals, even if the overall market is growing.</p>\n<div class=\"formula-box\">\n  <strong>Market Share (%) =</strong> (Sales of the business ÷ Total sales in the market) &times; 100\n</div>\n<p><strong>Worked Example (Shinz Ltd):</strong><br>\nThe car washing market in Littlelong = £460,000.<br>\nShinz Ltd holds 40% market share.<br>\nValue = 40% &times; £460,000 = <strong>£184,000</strong></p>\n<p><strong>Worked Example (Combined merger):</strong><br>\nShinz Ltd (40%) + Littlelong Motors (10%) = <strong>50% combined = £230,000</strong></p>\n<p><strong>Key warning:</strong> If the total market grows by 30% but a business''s sales only grow by 20%, that business''s market share has actually <em>fallen</em> — even though its sales went up. Market share is always relative to the total market.</p>\n<ul>\n  <li>Market share rises → more competitive, greater pricing power, stronger negotiating position with suppliers.</li>\n  <li>Market share falls → rivals growing faster, business losing ground even if its own sales are rising.</li>\n</ul>", "question": "A business''s sales grow by 20% while the total market grows by 30% over the same period. What happens to the business''s market share?", "options": ["It falls, since market share is relative to the market", "It cannot be determined without knowing profit figures", "It stays exactly the same", "It rises, because the business''s sales increased"]}'::jsonb, '{"answer": 0, "explain": "The card''s key warning states that if total market sales grow faster than a business''s own sales, its market share falls even though its sales have risen, because market share is always relative to the total market."}'::jsonb),
('business:1-6-business-growth:learn:42784fcb', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'learn', 'mcq', 1, '{"readingTitle": "Real-World Case Studies in Business Growth", "reading": "<div class=\"case-study-box\">\n  <h4>Case Study: Apple — Organic Growth</h4>\n  <p>Apple was started in 1976 and has grown to become the largest company in the world — almost entirely through <strong>organic growth</strong>. Rather than buying many other businesses, Apple focused on researching and developing its own products: the MacBook Pro, iPhone, iPad, and Apple Pay. Apple has taken over only a very small number of businesses in its entire history.</p>\n  <p>Apple also invested heavily in innovative marketing — introducing new products around September each year, using catchy music and minimalistic advertising to build a powerful global brand. Revenue grew from $33,300 in 1976 to $49.6 billion in 2016.</p>\n  <p><strong>Takeaway:</strong> Organic growth through product innovation and brand-building allowed Apple to maintain complete strategic control, resulting in one of the world''s most profitable companies without relying on expensive acquisitions.</p>\n</div>\n<div class=\"case-study-box\">\n  <h4>Case Study: Boohoo — External Growth</h4>\n  <p>Boohoo started in 2006 as an online fashion retailer targeting 16–24 year olds and initially grew organically via social media and website development. However, in 2020/2021 it shifted to <strong>external growth</strong>, acquiring well-known brands including Debenhams, Oasis, Burton, and Dorothy Perkins. This instantly gave Boohoo access to millions of customers across different demographics.</p>\n  <p>However, taking on so many businesses simultaneously created significant management challenges — controlling a much larger organisation increased costs and risked reducing overall efficiency and profitability.</p>\n  <p><strong>Takeaway:</strong> External growth gave Boohoo rapid access to new markets, but managing multiple acquisitions simultaneously increased the risk of losing control and damaging the original brand.</p>\n</div>\n<div class=\"case-study-box\">\n  <h4>Case Study: Greggs — Choosing Between Growth Methods</h4>\n  <p>Greggs is a ''food-on-the-go'' brand with 20,000 employees and a growing vegan product range (vegan sausage rolls launched 2019 boosted sales by 9.6% in 7 weeks). Greggs considered two external growth options: (1) a <strong>backward vertical merger</strong> with a flour producer to secure raw material supply and reduce costs; (2) a <strong>horizontal takeover</strong> of a rival food-on-the-go brand to eliminate competition and rapidly increase market share.</p>\n  <p><strong>Takeaway:</strong> Different growth strategies serve different purposes. Backward vertical growth secures supplies and cuts costs; horizontal takeover removes competition and boosts market share rapidly. The best choice depends on the business''s specific aims and context.</p>\n</div>", "question": "Which case study business grew almost entirely through organic growth, taking over only a very small number of businesses in its history?", "options": ["Boohoo", "Apple", "None of these — all three grew solely through mergers", "Greggs"]}'::jsonb, '{"answer": 1, "explain": "The card states Apple grew to become the largest company in the world almost entirely through organic growth, focusing on researching and developing its own products rather than buying other businesses."}'::jsonb),
('business:1-6-business-growth:misc:2176ee6c', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students describe organic growth as simply ''growing your business naturally'' without specifying a method.</p><p><strong>✅ The correct idea:</strong> Organic growth has specific methods: increasing output, developing new products, gaining new customers, and increasing market share. Always name the specific method and explain how it works in the context of the business.</p>", "question": "What does an examiner expect a student to do when answering a question on organic growth, rather than just saying it means ''growing naturally''?", "options": ["Just state that the business is getting bigger", "Compare it to a takeover", "Give the exact date the business started", "Name the specific method, e.g. new products"]}'::jsonb, '{"answer": 3, "explain": "Organic growth has specific named methods that must be identified and explained in context, not just described vaguely as ''growing naturally''."}'::jsonb),
('business:1-6-business-growth:misc:920ebd06', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students confuse mergers and takeovers and use the terms interchangeably.</p><p><strong>✅ The correct idea:</strong> A merger is by mutual agreement — both businesses choose to join. A takeover is when one business buys more than 50% of another''s shares to gain control — the target may not have wanted this. The examiner will penalise you for using these interchangeably.</p>", "question": "How does a takeover differ from a merger?", "options": ["A takeover requires both businesses to rebrand under a new name", "A takeover is buying over 50% of shares to gain control", "A takeover and a merger are simply two names for the same process", "A takeover always involves two businesses of equal size"]}'::jsonb, '{"answer": 1, "explain": "A merger is by mutual agreement, while a takeover is when one business buys a controlling stake (over 50% of shares) — using the terms interchangeably will be penalised."}'::jsonb),
('business:1-6-business-growth:misc:e3b7468f', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students say a jam maker buying a fruit farm is horizontal growth because both involve food.</p><p><strong>✅ The correct idea:</strong> Horizontal growth means SAME stage of production in the SAME industry. A jam maker and a fruit farm are at DIFFERENT stages — one supplies the other. This is BACKWARD VERTICAL growth. Think about the supply chain direction.</p>", "question": "A jam manufacturer buys a fruit farm that supplies it with fruit. What type of growth is this?", "options": ["Forward vertical growth, because the farm sells its fruit onward", "Backward vertical growth, since the farm supplies the jam factory", "Diversification, because farming and manufacturing are different activities", "Horizontal growth, because both businesses are involved with food"]}'::jsonb, '{"answer": 1, "explain": "This is backward vertical growth, not horizontal growth, because the farm supplies the jam maker — they are at different stages of production, not the same stage in the same industry."}'::jsonb),
('business:1-6-business-growth:misc:5474f79d', 'business', 'business:1-6-business-growth', '1.6 Business Growth', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Students describe all external growth as ''diversification''.</p><p><strong>✅ The correct idea:</strong> Diversification is specifically when a business joins with a company in a completely UNRELATED industry. If the businesses are connected by the supply chain or operate in the same industry, it is horizontal or vertical, NOT diversification.</p>", "question": "Which best describes when a business merger or takeover counts as ''diversification''?", "options": ["Whenever any external growth takes place", "Only when joining a totally unrelated industry", "Whenever a business takes over a competitor", "Whenever a business merges with a supplier"]}'::jsonb, '{"answer": 1, "explain": "Diversification specifically means joining an unrelated industry — if the businesses are linked through the supply chain or same industry, it is vertical or horizontal growth instead, not diversification."}'::jsonb)
